def update_kubeconfig(events, context):
    import subprocess
    result = subprocess.run(
        ['aws', 'eks', 'update-kubeconfig',
         '--name', events['ClusterName'],
         '--region', 'us-east-1'],
        capture_output=True, text=True
    )
    return {'stdout': result.stdout, 'returncode': result.returncode}

def check_health(events, context):
    import subprocess
    result = subprocess.run(
        ['kubectl', 'get', 'pods', '-n', events['Namespace'],
         '--field-selector=status.phase!=Running', '-o', 'wide'],
        capture_output=True, text=True
    )
    return {'unhealthy_pods': result.stdout, 'count': len(result.stdout.strip().split('\n')) - 1}

def verify(events, context):
    import subprocess
    result = subprocess.run(
        ['kubectl', 'get', 'pods', '-n', events['Namespace'],
         '-l', 'app=' + events['Deployment'],
         '--field-selector=status.phase=Running', '-o', 'name'],
        capture_output=True, text=True
    )
    pods = [p for p in result.stdout.strip().split('\n') if p]
    return {'running_pods': len(pods), 'pod_names': pods}
